mapper.select:
SELECT
FROM `order` o LEFT JOIN user buyer ON o.buyer_id = buyer.id LEFT JOIN user seller ON o.seller_id = seller.id LEFT JOIN product p ON o.product_id = p.id LEFT JOIN address a ON o.address_id = a.id WHERE o.deleted = 0
AND o.buyer_id = #{buyerId}
AND o.seller_id = #{sellerId}
AND o.status = #{status}
ORDER BY o.create_time DESC

SELECT o.status AS status, COUNT(*) AS order_count FROM `order` o WHERE o.deleted = 0 AND o.seller_id = #{sellerId}
AND o.create_time >= #{startTime}
GROUP BY o.status ORDER BY CASE o.status WHEN 'PENDING_PAYMENT' THEN 1 WHEN 'PAYMENT_PROCESSING' THEN 2 WHEN 'PENDING_SHIPMENT' THEN 3 WHEN 'SHIPPED' THEN 4 WHEN 'COMPLETED' THEN 5 WHEN 'CANCELLED' THEN 6 ELSE 99 END

SELECT o.product_id AS product_id, COALESCE(NULLIF(p.title, ''), '商品已删除') AS product_title, COALESCE(NULLIF(p.image, ''), '/placeholder.png') AS product_image, COUNT(*) AS order_count, COALESCE(SUM(o.quantity), 0) AS quantity_sold, COALESCE(SUM(o.total_price), 0) AS order_amount, p.stock AS current_stock FROM `order` o LEFT JOIN product p ON o.product_id = p.id WHERE o.deleted = 0 AND o.seller_id = #{sellerId}
AND o.create_time >= #{startTime}
GROUP BY o.product_id, p.title, p.image, p.stock ORDER BY quantity_sold DESC, order_amount DESC LIMIT #{limit}

SELECT
FROM `order` o LEFT JOIN user buyer ON o.buyer_id = buyer.id LEFT JOIN user seller ON o.seller_id = seller.id LEFT JOIN product p ON o.product_id = p.id LEFT JOIN address a ON o.address_id = a.id WHERE o.deleted = 0 AND o.seller_id = #{sellerId}
AND o.create_time >= #{startTime}
ORDER BY o.create_time DESC LIMIT #{limit}
